const body = ($('Receive Lead').first().json.body || {});
const token = (body.agent_token || '').trim();
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const query = uuidRe.test(token)
  ? `SELECT id FROM clients WHERE token = '${token}'::uuid AND status = 'active' LIMIT 1`
  : 'SELECT null::uuid AS id WHERE false';
return [{ json: { client_query: query } }];

const client_id = ($input.first().json.id || null);
if (!client_id) return [{ json: { lead_query: 'SELECT 1' } }];
const body = $('Receive Lead').first().json.body;
const esc = v => (v || '').toString().replace(/'/g, "''");
const meta = JSON.stringify({ property_address: body.property_address || null, price_range: body.price_range || null, beds: body.beds || null }).replace(/'/g, "''");
return [{ json: { lead_query: `INSERT INTO leads (client_id, lead_name, email, phone, source, lead_message, status, metadata) VALUES ('${client_id}'::uuid, '${esc(body.lead_name)}', '${esc(body.email)}', '${esc(body.phone)}', '${esc(body.source)}', '${esc(body.lead_message)}', 'new', '${meta}'::jsonb)` } }];
